<template><div class="chat-page"><QuickRepliesPage v-if="quickPage" @close="quickPage=false" @select="selectQuick"/><template v-else><TopBar :title="conversation.buyerName||'买家咨询'" :tag="conversation.orderStatus" back fallback="/messages"><button @click="action('操作')"><CheckSquare/></button><button @click="action('买家资料')"><CircleUserRound/></button></TopBar><main class="message-stream"><p v-if="error" class="error">{{error}}</p><div v-for="(m,i) in messages" :key="m.id"><time v-if="i===0||messages[i-1].createdAt!==m.createdAt">{{formatBeijingDateTime(m.createdAt)}}</time><MessageBubble :item="m"/></div></main><div v-if="picker" class="card-picker"><input v-if="picker==='products'" v-model="keyword" placeholder="搜索商品" @input="loadChoices"><button v-for="x in choices" :key="x.id" @click="sendCard(x)"><b>{{picker==='products'?x.title:x.orderNo}}</b><span>{{picker==='products'?'¥'+x.price:x.productTitle+' · ¥'+x.amount+' · '+x.statusText}}</span></button></div><QuickActionPanel v-if="more" @action="action"/><ChatComposer ref="composer" @openQuick="quickPage=true" @send="send" @upload="upload" @more="more=!more" @action="action"/><div v-if="tip" class="toast" @click="tip=''">{{tip}}功能暂为占位</div></template></div></template><script setup lang="ts">import{onBeforeUnmount,onMounted,ref,nextTick,watch}from'vue';import{CheckSquare,CircleUserRound}from'lucide-vue-next';import{route}from'../router';import{formatBeijingDateTime}from'../utils/time';import{compressImage,getVideoThumbnail,isImage,isVideo}from'../utils/chatMedia';import TopBar from'../components/TopBar.vue';import MessageBubble from'../components/MessageBubble.vue';import ChatComposer from'../components/ChatComposer.vue';import QuickActionPanel from'../components/QuickActionPanel.vue';import QuickRepliesPage from'../components/QuickRepliesPage.vue';const conversation=ref<any>({}),messages=ref<any[]>([]),error=ref(''),more=ref(false),tip=ref(''),quickPage=ref(false),composer=ref<any>();const selectQuick=(content:string)=>{quickPage.value=false;nextTick(()=>composer.value?.replace(content))};const picker=ref(''),choices=ref<any[]>([]),keyword=ref(''),hasOrders=ref(false);const action=(x:any)=>{const v=Array.isArray(x)?x[0]:x;if(v==='商品'||v==='推荐商品')openPicker('products');else if(v==='订单'||v==='核对订单')openPicker('orders');else tip.value=v};async function openPicker(k:string){picker.value=k;more.value=false;await loadChoices()}async function loadChoices(){const id=route.value.chatId;if(!id)return;const q=picker.value==='products'&&keyword.value?'?keyword='+encodeURIComponent(keyword.value):'';const r=await fetch(`/api/koshop-seller/messages/conversations/${id}/${picker.value}${q}`),j=await r.json();choices.value=j.items||[]}async function sendCard(x:any){const product=picker.value==='products',payload=product?{koshopType:'product_card',productId:x.id,title:x.title,price:x.price,cover:x.cover,url:`/products/${x.id}`,text:`[商品] ${x.title}`}:{koshopType:'order_card',orderId:x.id,orderNo:x.orderNo,productTitle:x.productTitle,amount:x.amount,statusText:x.statusText,createdAt:x.createdAt,text:`[订单] ${x.orderNo}`};await fetch(`/api/koshop-seller/messages/conversations/${route.value.chatId}/cards`,{method:'POST',headers:{'content-type':'application/json'},body:JSON.stringify(payload)});picker.value='';await load(true)}let timer:number|undefined,loading=false,lastRead:any;const nearBottom=()=>document.documentElement.scrollHeight-innerHeight-scrollY<160;const scrollBottom=()=>nextTick(()=>scrollTo(0,document.body.scrollHeight));async function read(id:string,messageId:any){if(messageId===undefined||messageId===lastRead)return;try{await fetch(`/api/koshop-seller/messages/conversations/${id}/read`,{method:'POST'});lastRead=messageId}catch{}}async function load(force=false){const id=route.value.chatId;if(!id||loading)return;loading=true;const shouldScroll=force||nearBottom();try{const[cr,mr]=await Promise.all([fetch(`/api/koshop-seller/messages/conversations/${id}`),fetch(`/api/koshop-seller/messages/conversations/${id}/messages`)]),[c,m]=await Promise.all([cr.json(),mr.json()]);if(!cr.ok||!mr.ok)throw Error(m.message||c.message);conversation.value=c.conversation||{};messages.value=m.items||[];error.value='';const latest=messages.value.at(-1);if(latest)read(id,latest.id);if(shouldScroll)scrollBottom()}catch(e:any){error.value=e.message||'消息加载失败'}finally{loading=false}}async function send(content:string){const id=route.value.chatId;if(!id)return;error.value='';try{const r=await fetch(`/api/koshop-seller/messages/conversations/${id}/messages`,{method:'POST',headers:{'content-type':'application/json'},body:JSON.stringify({content})}),j=await r.json();if(!r.ok||!j.ok)throw Error(j.message);await load(true)}catch(e:any){error.value=e.message||'发送失败，请稍后重试'}}async function upload(file:File,done:()=>void){const id=route.value.chatId;if(!id)return done();const type=isVideo(file)?'video':isImage(file)?'image':'';if(!type){error.value='文件格式不支持';return done()}error.value='正在上传...';const uploadFile=type==='image'?await compressImage(file):file;const thumbnail=type==='video'?await getVideoThumbnail(file):null;const fd=new FormData();fd.append('file',uploadFile,file.name);fd.append('type',type);if(thumbnail)fd.append('thumbnail',thumbnail,file.name+'.thumbnail.jpg');try{const r=await fetch(`/api/koshop-seller/messages/conversations/${id}/upload`,{method:'POST',body:fd}),j=await r.json();if(!r.ok||!j.ok)throw Error(j.message);await load(true)}catch(e:any){error.value=e.message||'上传失败'}finally{done()}}function stop(){if(timer!==undefined){clearInterval(timer);timer=undefined}}function start(){stop();if(!document.hidden)timer=window.setInterval(()=>load(),2000)}function visibility(){if(document.hidden)stop();else{load();start()}}function open(){stop();conversation.value={};messages.value=[];lastRead=undefined;load(true);start()}watch(()=>route.value.chatId,open);onMounted(()=>{open();document.addEventListener('visibilitychange',visibility)});onBeforeUnmount(()=>{stop();document.removeEventListener('visibilitychange',visibility)})</script>
